SELECT * FROM kodik_content
ORDER BY ${sortBy} ${order}
LIMIT #{limit} OFFSET #{offset}

SELECT DISTINCT c.* FROM kodik_content c
INNER JOIN kodik_episode_variant ev ON c.id = ev.content_id
WHERE ev.mp4_link IS NOT NULL
AND c.updated_at > #{updatedSince}
ORDER BY c.updated_at DESC
LIMIT #{limit} OFFSET #{offset}
